contracts/AgentCovenant.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./utils/Pausable.sol";

/**
 * @title AgentCovenant
 * @notice Individual covenant agreement between two AI agents
 * @dev Stores terms, handles disputes, manages escrow
 * Includes ReentrancyGuard and Pausable for security
 */
contract AgentCovenant is ReentrancyGuard, Pausable {

    // ============ Enums ============

    enum CovenantStatus {
        PENDING,      // Waiting for counterparty acceptance
        ACTIVE,       // Covenant is active
        FULFILLED,    // Terms completed successfully
        DISPUTED,     // Under dispute
        RESOLVED,     // Dispute resolved
        EXPIRED,      // Past deadline
        BREACHED      // Terms violated
    }

    enum Party {
        INITIATOR,
        COUNTERPARTY
    }

    // ============ Structs ============

    struct CovenantTerms {
        bytes32 covenantType;      // TASK, ALLIANCE, ESCROW, etc.
        string termsIPFSHash;      // Detailed terms stored on IPFS
        uint256 createdAt;         // Creation timestamp
        uint256 expiresAt;         // Expiration timestamp
        uint256 stakeAmount;       // Amount staked by initiator
    }

    struct Milestone {
        string description;
        uint256 paymentAmount;
        bool completed;
        bool paid;
        uint256 completedAt;
    }

    // ============ State Variables ============

    address public immutable initiator;
    address public immutable counterparty;
    CovenantTerms public terms;
    CovenantStatus public status;

    Milestone[] public milestones;
    uint256 public totalMilestonePayments;
    uint256 public remainingBalance;

    address public feeRecipient;
    uint256 public protocolFeeBps;

    mapping(address => bool) public hasAccepted;
    mapping(address => bytes32) public agentCommitments; // Hashed commitments for milestones

    address public disputeResolver;
    string public disputeReason;
    uint256 public disputedAt;

    // ============ Events ============

    event CovenantAccepted(address indexed by);
    event CovenantActivated();
    event MilestoneAdded(uint256 indexed index, string description, uint256 payment);
    event MilestoneCompleted(uint256 indexed index, address indexed by);
    event MilestonePaid(uint256 indexed index, uint256 amount);
    event DisputeRaised(address indexed by, string reason);
    event DisputeResolved(address indexed resolver, uint256 initiatorAward, uint256 counterpartyAward);
    event CovenantFulfilled();
    event CovenantBreached(address indexed by, string reason);
    event FundsWithdrawn(address indexed by, uint256 amount);

    // ============ Modifiers ============

    modifier onlyParty() {
        require(
            msg.sender == initiator || msg.sender == counterparty,
            "Not a party"
        );
        _;
    }

    modifier onlyInitiator() {
        require(msg.sender == initiator, "Not initiator");
        _;
    }

    modifier onlyActive() {
        require(status == CovenantStatus.ACTIVE, "Not active");
        _;
    }

    // ============ Constructor ============

    constructor(
        address _initiator,
        address _counterparty,
        bytes32 _covenantType,
        string memory _termsIPFSHash,
        uint256 _duration,
        uint256 _stakeAmount,
        address _feeRecipient,
        uint256 _protocolFeeBps
    ) payable {
        initiator = _initiator;
        counterparty = _counterparty;
        feeRecipient = _feeRecipient;
        protocolFeeBps = _protocolFeeBps;
        remainingBalance = msg.value;

        terms = CovenantTerms({
            covenantType: _covenantType,
            termsIPFSHash: _termsIPFSHash,
            createdAt: block.timestamp,
            expiresAt: block.timestamp + _duration,
            stakeAmount: _stakeAmount
        });

        status = CovenantStatus.PENDING;
        hasAccepted[_initiator] = true; // Initiator auto-accepts
    }

    // ============ Core Functions ============

    /**
     * @notice Counterparty accepts the covenant
     */
    function acceptCovenant() external whenNotPaused nonReentrant {
        require(msg.sender == counterparty, "Not counterparty");
        require(status == CovenantStatus.PENDING, "Not pending");
        require(block.timestamp < terms.expiresAt, "Expired");

        hasAccepted[counterparty] = true;
        status = CovenantStatus.ACTIVE;

        emit CovenantAccepted(counterparty);
        emit CovenantActivated();
    }

    /**
     * @notice Add a milestone with payment
     */
    function addMilestone(
        string calldata _description,
        uint256 _paymentAmount
    ) external whenNotPaused nonReentrant onlyInitiator onlyActive {
        require(_paymentAmount <= remainingBalance, "Insufficient balance");

        milestones.push(Milestone({
            description: _description,
            paymentAmount: _paymentAmount,
            completed: false,
            paid: false,
            completedAt: 0
        }));

        totalMilestonePayments += _paymentAmount;

        emit MilestoneAdded(milestones.length - 1, _description, _paymentAmount);
    }

    /**
     * @notice Mark a milestone as completed
     */
    function completeMilestone(uint256 _milestoneIndex) external onlyActive {
        require(_milestoneIndex < milestones.length, "Invalid milestone");
        Milestone storage milestone = milestones[_milestoneIndex];
        require(!milestone.completed, "Already completed");

        milestone.completed = true;
        milestone.completedAt = block.timestamp;

        emit MilestoneCompleted(_milestoneIndex, msg.sender);
    }

    /**
     * @notice Pay out a completed milestone
     */
    function payMilestone(uint256 _milestoneIndex) external whenNotPaused nonReentrant onlyInitiator onlyActive {
        require(_milestoneIndex < milestones.length, "Invalid milestone");
        Milestone storage milestone = milestones[_milestoneIndex];
        require(milestone.completed, "Not completed");
        require(!milestone.paid, "Already paid");

        milestone.paid = true;
        remainingBalance -= milestone.paymentAmount;

        // Calculate protocol fee
        uint256 fee = (milestone.paymentAmount * protocolFeeBps) / 10000;
        uint256 payment = milestone.paymentAmount - fee;

        // Pay fee
        (bool feeSuccess, ) = feeRecipient.call{value: fee}("");
        require(feeSuccess, "Fee transfer failed");

        // Pay counterparty
        (bool paySuccess, ) = counterparty.call{value: payment}("");
        require(paySuccess, "Payment failed");

        emit MilestonePaid(_milestoneIndex, payment);

        // Check if all milestones paid
        if (_allMilestonesPaid()) {
            status = CovenantStatus.FULFILLED;
            emit CovenantFulfilled();
        }
    }

    /**
     * @notice Raise a dispute
     */
    function raiseDispute(string calldata _reason) external whenNotPaused nonReentrant onlyParty {
        require(
            status == CovenantStatus.ACTIVE || status == CovenantStatus.PENDING,
            "Cannot dispute"
        );

        status = CovenantStatus.DISPUTED;
        disputeReason = _reason;
        disputedAt = block.timestamp;

        emit DisputeRaised(msg.sender, _reason);
    }

    /**
     * @notice Resolve a dispute (called by factory/disputeDAO)
     */
    function resolveDispute(
        uint256 _initiatorAward,
        uint256 _counterpartyAward
    ) external {
        require(status == CovenantStatus.DISPUTED, "Not disputed");
        require(
            _initiatorAward + _counterpartyAward <= remainingBalance,
            "Awards exceed balance"
        );

        status = CovenantStatus.RESOLVED;
        disputeResolver = msg.sender;

        // Distribute awards
        if (_initiatorAward > 0) {
            remainingBalance -= _initiatorAward;
            (bool success, ) = initiator.call{value: _initiatorAward}("");
            require(success, "Initiator award failed");
        }

        if (_counterpartyAward > 0) {
            remainingBalance -= _counterpartyAward;
            (bool success, ) = counterparty.call{value: _counterpartyAward}("");
            require(success, "Counterparty award failed");
        }

        // Return remaining to initiator
        if (remainingBalance > 0) {
            uint256 refund = remainingBalance;
            remainingBalance = 0;
            (bool success, ) = initiator.call{value: refund}("");
            require(success, "Refund failed");
        }

        emit DisputeResolved(msg.sender, _initiatorAward, _counterpartyAward);
    }

    /**
     * @notice Declare covenant breached
     */
    function declareBreach(string calldata _reason) external onlyParty {
        require(status == CovenantStatus.ACTIVE, "Not active");
        require(block.timestamp > terms.expiresAt, "Not expired yet");

        status = CovenantStatus.BREACHED;

        // Return remaining funds to initiator
        if (remainingBalance > 0) {
            uint256 refund = remainingBalance;
            remainingBalance = 0;
            (bool success, ) = initiator.call{value: refund}("");
            require(success, "Refund failed");
        }

        emit CovenantBreached(msg.sender, _reason);
    }

    /**
     * @notice Withdraw remaining funds (initiator only, after expiry)
     */
    function withdrawRemaining() external onlyInitiator {
        require(
            status == CovenantStatus.EXPIRED || 
            status == CovenantStatus.BREACHED ||
            status == CovenantStatus.FULFILLED ||
            block.timestamp > terms.expiresAt,
            "Cannot withdraw yet"
        );

        require(remainingBalance > 0, "No balance");

        uint256 amount = remainingBalance;
        remainingBalance = 0;

        (bool success, ) = initiator.call{value: amount}("");
        require(success, "Withdraw failed");

        emit FundsWithdrawn(initiator, amount);
    }

    // ============ View Functions ============

    function getMilestoneCount() external view returns (uint256) {
        return milestones.length;
    }

    function getMilestone(uint256 _index) external view returns (Milestone memory) {
        require(_index < milestones.length, "Invalid index");
        return milestones[_index];
    }

    function isActive() external view returns (bool) {
        return status == CovenantStatus.ACTIVE;
    }

    function timeRemaining() external view returns (uint256) {
        if (block.timestamp >= terms.expiresAt) return 0;
        return terms.expiresAt - block.timestamp;
    }

    // ============ Internal Functions ============

    function _allMilestonesPaid() internal view returns (bool) {
        for (uint256 i = 0; i < milestones.length; i++) {
            if (!milestones[i].paid) return false;
        }
        return true;
    }

    // Allow receiving ETH
    receive() external payable {
        remainingBalance += msg.value;
    }
}

contracts/AgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./utils/Pausable.sol";

/**
 * @title AgentRegistry
 * @notice Discovery layer for AI agents - register skills, find collaborators
 * @dev Part of COVENANT Protocol for agent coordination
 * Includes ReentrancyGuard and Pausable for security
 */
contract AgentRegistry is ReentrancyGuard, Pausable {

    // ============ Structs ============

    struct AgentProfile {
        address agentAddress;
        string metadataURI;         // IPFS hash with agent details
        uint256[] skills;           // Skill IDs
        string[] skillNames;        // Human-readable skill names
        uint256 reputationScore;
        bool isActive;
        uint256 registeredAt;
        uint256 lastActive;
        uint256 covenantsCompleted;
        uint256 tasksCompleted;
        uint256 totalEarned;
    }

    struct Skill {
        uint256 id;
        string name;
        string description;
        uint256 agentCount;
    }

    // ============ State Variables ============

    mapping(address => AgentProfile) public agents;
    mapping(uint256 => Skill) public skills;
    mapping(uint256 => address[]) public skillToAgents;
    mapping(string => uint256) public skillNameToId;

    address[] public allAgents;
    uint256 public nextSkillId = 1;
    uint256 public totalAgents = 0;

    address public owner;
    uint256 public registrationFee = 0.001 ether;

    // ============ Events ============

    event AgentRegistered(
        address indexed agent,
        string metadataURI,
        uint256[] skills,
        uint256 timestamp
    );

    event AgentUpdated(
        address indexed agent,
        string metadataURI,
        uint256[] skills,
        uint256 timestamp
    );

    event AgentDeactivated(address indexed agent, uint256 timestamp);
    event AgentReactivated(address indexed agent, uint256 timestamp);

    event SkillAdded(uint256 indexed skillId, string name, string description);
    event SkillAssigned(address indexed agent, uint256 indexed skillId);

    event ActivityRecorded(
        address indexed agent,
        uint256 covenantsCompleted,
        uint256 tasksCompleted,
        uint256 totalEarned
    );

    // ============ Modifiers ============

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyRegistered() {
        require(agents[msg.sender].isActive, "Not registered");
        _;
    }

    modifier validSkillIds(uint256[] calldata _skillIds) {
        for (uint i = 0; i < _skillIds.length; i++) {
            require(_skillIds[i] > 0 && _skillIds[i] < nextSkillId, "Invalid skill ID");
        }
        _;
    }

    // ============ Constructor ============

    constructor() {
        owner = msg.sender;

        // Initialize default skills
        _addSkill("Smart Contract Development", "Writing and auditing Solidity contracts");
        _addSkill("Data Analysis", "On-chain and off-chain data analysis");
        _addSkill("Trading", "DeFi trading and arbitrage strategies");
        _addSkill("Content Creation", "Documentation, social media, marketing");
        _addSkill("Security Auditing", "Smart contract security reviews");
        _addSkill("Machine Learning", "AI/ML model training and inference");
        _addSkill("DevOps", "Infrastructure and deployment");
        _addSkill("Community Management", "Discord, forums, governance");
    }

    // ============ Core Functions ============

    /**
     * @notice Register as an AI agent
     * @param _metadataURI IPFS hash with agent details (name, description, portfolio)
     * @param _skillIds Array of skill IDs this agent has
     */
    function registerAgent(
        string calldata _metadataURI,
        uint256[] calldata _skillIds
    ) external payable whenNotPaused nonReentrant validSkillIds(_skillIds) {
        require(!agents[msg.sender].isActive, "Already registered");
        require(msg.value >= registrationFee, "Insufficient fee");

        // Refund excess
        if (msg.value > registrationFee) {
            (bool success, ) = msg.sender.call{value: msg.value - registrationFee}("");
            require(success, "Refund failed");
        }

        // Build skill names array
        string[] memory skillNames = new string[](_skillIds.length);
        for (uint i = 0; i < _skillIds.length; i++) {
            skillNames[i] = skills[_skillIds[i]].name;
            skillToAgents[_skillIds[i]].push(msg.sender);
            skills[_skillIds[i]].agentCount++;
        }

        agents[msg.sender] = AgentProfile({
            agentAddress: msg.sender,
            metadataURI: _metadataURI,
            skills: _skillIds,
            skillNames: skillNames,
            reputationScore: 0,
            isActive: true,
            registeredAt: block.timestamp,
            lastActive: block.timestamp,
            covenantsCompleted: 0,
            tasksCompleted: 0,
            totalEarned: 0
        });

        allAgents.push(msg.sender);
        totalAgents++;

        emit AgentRegistered(msg.sender, _metadataURI, _skillIds, block.timestamp);
    }

    /**
     * @notice Update agent profile
     */
    function updateProfile(
        string calldata _metadataURI,
        uint256[] calldata _skillIds
    ) external onlyRegistered validSkillIds(_skillIds) {
        AgentProfile storage agent = agents[msg.sender];

        // Remove from old skills
        for (uint i = 0; i < agent.skills.length; i++) {
            _removeAgentFromSkill(msg.sender, agent.skills[i]);
        }

        // Add to new skills
        string[] memory skillNames = new string[](_skillIds.length);
        for (uint i = 0; i < _skillIds.length; i++) {
            skillNames[i] = skills[_skillIds[i]].name;
            skillToAgents[_skillIds[i]].push(msg.sender);
            skills[_skillIds[i]].agentCount++;
        }

        agent.metadataURI = _metadataURI;
        agent.skills = _skillIds;
        agent.skillNames = skillNames;
        agent.lastActive = block.timestamp;

        emit AgentUpdated(msg.sender, _metadataURI, _skillIds, block.timestamp);
    }

    /**
     * @notice Deactivate agent profile
     */
    function deactivate() external onlyRegistered {
        agents[msg.sender].isActive = false;
        emit AgentDeactivated(msg.sender, block.timestamp);
    }

    /**
     * @notice Reactivate agent profile
     */
    function reactivate() external {
        require(agents[msg.sender].agentAddress != address(0), "Not registered");
        require(!agents[msg.sender].isActive, "Already active");
        agents[msg.sender].isActive = true;
        agents[msg.sender].lastActive = block.timestamp;
        emit AgentReactivated(msg.sender, block.timestamp);
    }

    /**
     * @notice Record agent activity (called by other contracts)
     */
    function recordActivity(
        address _agent,
        uint256 _covenantsCompleted,
        uint256 _tasksCompleted,
        uint256 _totalEarned
    ) external {
        require(agents[_agent].isActive, "Agent not active");

        AgentProfile storage agent = agents[_agent];
        agent.covenantsCompleted += _covenantsCompleted;
        agent.tasksCompleted += _tasksCompleted;
        agent.totalEarned += _totalEarned;
        agent.lastActive = block.timestamp;

        // Simple reputation calculation
        agent.reputationScore = 
            agent.covenantsCompleted * 10 +
            agent.tasksCompleted * 5 +
            (agent.totalEarned / 1e18); // 1 ETH = 1 rep point

        emit ActivityRecorded(
            _agent,
            agent.covenantsCompleted,
            agent.tasksCompleted,
            agent.totalEarned
        );
    }

    // ============ Discovery Functions ============

    /**
     * @notice Find agents by skill
     */
    function findAgentsBySkill(uint256 _skillId) external view returns (address[] memory) {
        return skillToAgents[_skillId];
    }

    /**
     * @notice Find agents by multiple skills (must have all)
     */
    function findAgentsBySkills(uint256[] calldata _skillIds) external view returns (address[] memory) {
        if (_skillIds.length == 0) return new address[](0);

        address[] memory candidates = skillToAgents[_skillIds[0]];
        address[] memory result = new address[](candidates.length);
        uint256 count = 0;

        for (uint i = 0; i < candidates.length; i++) {
            if (!agents[candidates[i]].isActive) continue;

            bool hasAllSkills = true;
            for (uint j = 1; j < _skillIds.length; j++) {
                if (!_hasSkill(candidates[i], _skillIds[j])) {
                    hasAllSkills = false;
                    break;
                }
            }

            if (hasAllSkills) {
                result[count] = candidates[i];
                count++;
            }
        }

        // Trim array
        address[] memory trimmed = new address[](count);
        for (uint i = 0; i < count; i++) {
            trimmed[i] = result[i];
        }

        return trimmed;
    }

    /**
     * @notice Get top agents by reputation
     */
    function getTopAgents(uint256 _limit) external view returns (address[] memory) {
        uint256 limit = _limit > allAgents.length ? allAgents.length : _limit;
        address[] memory topAgents = new address[](allAgents.length);

        // Copy all agents to memory
        for (uint i = 0; i < allAgents.length; i++) {
            topAgents[i] = allAgents[i];
        }

        // Simple bubble sort by reputation (for small datasets)
        for (uint i = 0; i < topAgents.length; i++) {
            for (uint j = i + 1; j < topAgents.length; j++) {
                if (agents[topAgents[j]].reputationScore > agents[topAgents[i]].reputationScore) {
                    address temp = topAgents[i];
                    topAgents[i] = topAgents[j];
                    topAgents[j] = temp;
                }
            }
        }

        // Return only requested limit
        address[] memory result = new address[](limit);
        for (uint i = 0; i < limit; i++) {
            result[i] = topAgents[i];
        }

        return result;
    }

    /**
     * @notice Get recently active agents
     */
    function getRecentlyActive(uint256 _limit, uint256 _withinSeconds) external view returns (address[] memory) {
        address[] memory recent = new address[](allAgents.length);
        uint256 count = 0;
        uint256 cutoff = block.timestamp - _withinSeconds;

        for (uint i = 0; i < allAgents.length; i++) {
            if (agents[allAgents[i]].isActive && agents[allAgents[i]].lastActive >= cutoff) {
                recent[count] = allAgents[i];
                count++;
                if (count >= _limit) break;
            }
        }

        address[] memory trimmed = new address[](count);
        for (uint i = 0; i < count; i++) {
            trimmed[i] = recent[i];
        }

        return trimmed;
    }

    // ============ Admin Functions ============

    function addSkill(string memory _name, string memory _description) external onlyOwner {
        _addSkill(_name, _description);
    }

    function setRegistrationFee(uint256 _newFee) external onlyOwner {
        registrationFee = _newFee;
    }

    function withdrawFees() external onlyOwner {
        (bool success, ) = owner.call{value: address(this).balance}("");
        require(success, "Withdraw failed");
    }

    // ============ View Functions ============

    function getAgent(address _agent) external view returns (AgentProfile memory) {
        return agents[_agent];
    }

    function getAgentSkills(address _agent) external view returns (uint256[] memory) {
        return agents[_agent].skills;
    }

    function getAllSkills() external view returns (Skill[] memory) {
        Skill[] memory allSkills = new Skill[](nextSkillId - 1);
        for (uint i = 1; i < nextSkillId; i++) {
            allSkills[i - 1] = skills[i];
        }
        return allSkills;
    }

    function isRegistered(address _agent) external view returns (bool) {
        return agents[_agent].isActive;
    }

    function getAgentCount() external view returns (uint256) {
        return totalAgents;
    }

    // ============ Internal Functions ============

    function _addSkill(string memory _name, string memory _description) internal {
        uint256 skillId = nextSkillId++;
        skills[skillId] = Skill({
            id: skillId,
            name: _name,
            description: _description,
            agentCount: 0
        });
        skillNameToId[_name] = skillId;
        emit SkillAdded(skillId, _name, _description);
    }

    function _removeAgentFromSkill(address _agent, uint256 _skillId) internal {
        address[] storage agentsWithSkill = skillToAgents[_skillId];
        for (uint i = 0; i < agentsWithSkill.length; i++) {
            if (agentsWithSkill[i] == _agent) {
                agentsWithSkill[i] = agentsWithSkill[agentsWithSkill.length - 1];
                agentsWithSkill.pop();
                skills[_skillId].agentCount--;
                break;
            }
        }
    }

    function _hasSkill(address _agent, uint256 _skillId) internal view returns (bool) {
        uint256[] storage agentSkills = agents[_agent].skills;
        for (uint i = 0; i < agentSkills.length; i++) {
            if (agentSkills[i] == _skillId) return true;
        }
        return false;
    }

    // Allow receiving ETH
    receive() external payable {}
}

contracts/CovenantFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./utils/Pausable.sol";
import "./AgentCovenant.sol";

/**
 * @title CovenantFactory
 * @notice Factory for creating new covenant agreements
 * @dev Deploys AgentCovenant instances and tracks them
 * Includes ReentrancyGuard and Pausable for security
 */
contract CovenantFactory is ReentrancyGuard, Pausable {

    // ============ State Variables ============

    /// @notice Array of all deployed covenants
    address[] public covenants;

    /// @notice Mapping from covenant address to creation timestamp
    mapping(address => uint256) public covenantCreationTime;

    /// @notice Mapping from agent pair to covenant address
    mapping(bytes32 => address) public agentPairToCovenant;

    /// @notice Protocol fee recipient (treasury)
    address public feeRecipient;

    /// @notice Protocol fee in basis points (100 = 1%)
    uint256 public protocolFeeBps = 100;

    /// @notice Minimum stake required to create covenants (in wei)
    uint256 public minimumStake = 0.01 ether;

    /// @notice Contract owner
    address public owner;

    // ============ Events ============

    event CovenantCreated(
        address indexed covenantAddress,
        address indexed initiator,
        address indexed counterparty,
        bytes32 covenantType,
        uint256 stakeAmount,
        uint256 timestamp
    );

    event FeeRecipientUpdated(address indexed oldRecipient, address indexed newRecipient);
    event ProtocolFeeUpdated(uint256 oldFee, uint256 newFee);
    event MinimumStakeUpdated(uint256 oldStake, uint256 newStake);

    // ============ Errors ============

    error InvalidAgentAddress();
    error CovenantAlreadyExists();
    error InsufficientStake();
    error Unauthorized();

    // ============ Modifiers ============

    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorized();
        _;
    }

    // ============ Constructor ============

    constructor(address _feeRecipient) {
        if (_feeRecipient == address(0)) revert InvalidAgentAddress();
        owner = msg.sender;
        feeRecipient = _feeRecipient;
    }

    // ============ External Functions ============

    /**
     * @notice Create a new covenant between two agents
     * @param _counterparty The other agent in the covenant
     * @param _covenantType Type of covenant (TASK, ALLIANCE, ESCROW, etc.)
     * @param _termsIPFSHash IPFS hash of detailed terms
     * @param _duration Duration of the covenant in seconds
     * @return covenantAddress Address of the newly created covenant
     */
    function createCovenant(
        address _counterparty,
        bytes32 _covenantType,
        string calldata _termsIPFSHash,
        uint256 _duration
    ) external payable whenNotPaused nonReentrant returns (address covenantAddress) {

        if (_counterparty == address(0) || _counterparty == msg.sender) {
            revert InvalidAgentAddress();
        }

        if (msg.value < minimumStake) {
            revert InsufficientStake();
        }

        // Check if covenant already exists between these agents
        bytes32 pairHash = keccak256(abi.encodePacked(
            msg.sender < _counterparty ? msg.sender : _counterparty,
            msg.sender < _counterparty ? _counterparty : msg.sender
        ));

        if (agentPairToCovenant[pairHash] != address(0)) {
            revert CovenantAlreadyExists();
        }

        // Calculate protocol fee
        uint256 protocolFee = (msg.value * protocolFeeBps) / 10000;
        uint256 stakeAmount = msg.value - protocolFee;

        // Transfer protocol fee
        (bool feeSuccess, ) = feeRecipient.call{value: protocolFee}("");
        require(feeSuccess, "Fee transfer failed");

        // Deploy new covenant
        AgentCovenant newCovenant = new AgentCovenant{
            value: stakeAmount
        }(
            msg.sender,
            _counterparty,
            _covenantType,
            _termsIPFSHash,
            _duration,
            stakeAmount,
            feeRecipient,
            protocolFeeBps
        );

        covenantAddress = address(newCovenant);
        covenants.push(covenantAddress);
        covenantCreationTime[covenantAddress] = block.timestamp;
        agentPairToCovenant[pairHash] = covenantAddress;

        emit CovenantCreated(
            covenantAddress,
            msg.sender,
            _counterparty,
            _covenantType,
            stakeAmount,
            block.timestamp
        );

        return covenantAddress;
    }

    /**
     * @notice Get total number of covenants created
     */
    function getCovenantCount() external view returns (uint256) {
        return covenants.length;
    }

    /**
     * @notice Get all covenants (with pagination)
     * @param _offset Starting index
     * @param _limit Maximum number to return
     */
    function getCovenants(uint256 _offset, uint256 _limit) 
        external 
        view 
        returns (address[] memory) 
    {
        uint256 end = _offset + _limit;
        if (end > covenants.length) {
            end = covenants.length;
        }

        address[] memory result = new address[](end - _offset);
        for (uint256 i = _offset; i < end; i++) {
            result[i - _offset] = covenants[i];
        }

        return result;
    }

    /**
     * @notice Check if a covenant exists between two agents
     */
    function covenantExists(address _agent1, address _agent2) 
        external 
        view 
        returns (bool) 
    {
        bytes32 pairHash = keccak256(abi.encodePacked(
            _agent1 < _agent2 ? _agent1 : _agent2,
            _agent1 < _agent2 ? _agent2 : _agent1
        ));
        return agentPairToCovenant[pairHash] != address(0);
    }

    // ============ Admin Functions ============

    function setFeeRecipient(address _newRecipient) external onlyOwner {
        emit FeeRecipientUpdated(feeRecipient, _newRecipient);
        feeRecipient = _newRecipient;
    }

    function setProtocolFee(uint256 _newFeeBps) external onlyOwner {
        require(_newFeeBps <= 1000, "Fee too high"); // Max 10%
        emit ProtocolFeeUpdated(protocolFeeBps, _newFeeBps);
        protocolFeeBps = _newFeeBps;
    }

    function setMinimumStake(uint256 _newMinimum) external onlyOwner {
        emit MinimumStakeUpdated(minimumStake, _newMinimum);
        minimumStake = _newMinimum;
    }

    function transferOwnership(address _newOwner) external onlyOwner {
        owner = _newOwner;
    }
}

contracts/ReputationStake.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./utils/Pausable.sol";

/**
 * @title ReputationStake
 * @notice Staking mechanism for agent reputation
 * @dev Agents stake tokens to build reputation, can be slashed for bad behavior
 * Includes ReentrancyGuard and Pausable for security
 */
contract ReputationStake is ReentrancyGuard, Pausable {

    // ============ Structs ============

    struct Stake {
        uint256 amount;
        uint256 since;
        uint256 unlockTime;
        bool withdrawn;
    }

    struct AgentProfile {
        uint256 totalStaked;
        uint256 reputationScore;
        uint256 successfulCovenants;
        uint256 breachedCovenants;
        uint256 lastActivity;
        bool isActive;
        string metadataURI; // IPFS URI with agent details
    }

    // ============ State Variables ============

    IERC20 public stakeToken;
    address public feeRecipient;

    mapping(address => AgentProfile) public agents;
    mapping(address => Stake[]) public agentStakes;
    mapping(address => bool) public authorizedSlashers;

    uint256 public minimumStake = 100 * 10**18; // 100 tokens
    uint256 public slashingPercentage = 1000; // 10%
    uint256 public lockPeriod = 7 days;
    uint256 public protocolFeeBps = 100; // 1%

    // Reputation calculation weights
    uint256 public stakeWeight = 40;
    uint256 public historyWeight = 30;
    uint256 public activityWeight = 30;

    uint256 public totalStaked;
    uint256 public totalAgents;

    // ============ Events ============

    event AgentRegistered(address indexed agent, string metadataURI);
    event StakeDeposited(address indexed agent, uint256 amount, uint256 unlockTime);
    event StakeWithdrawn(address indexed agent, uint256 amount);
    event ReputationUpdated(address indexed agent, uint256 newScore);
    event AgentSlashed(address indexed agent, uint256 amount, string reason);
    event RewardDistributed(address indexed agent, uint256 amount);

    // ============ Modifiers ============

    modifier onlyAuthorizedSlasher() {
        require(authorizedSlashers[msg.sender], "Not authorized");
        _;
    }

    modifier onlyRegistered() {
        require(agents[msg.sender].isActive, "Not registered");
        _;
    }

    // ============ Constructor ============

    constructor(address _stakeToken, address _feeRecipient) {
        stakeToken = IERC20(_stakeToken);
        feeRecipient = _feeRecipient;
        authorizedSlashers[msg.sender] = true; // Owner is slasher
    }

    // ============ Core Functions ============

    /**
     * @notice Register as an agent
     */
    function registerAgent(string calldata _metadataURI) external {
        require(!agents[msg.sender].isActive, "Already registered");

        agents[msg.sender] = AgentProfile({
            totalStaked: 0,
            reputationScore: 0,
            successfulCovenants: 0,
            breachedCovenants: 0,
            lastActivity: block.timestamp,
            isActive: true,
            metadataURI: _metadataURI
        });

        totalAgents++;

        emit AgentRegistered(msg.sender, _metadataURI);
    }

    /**
     * @notice Stake tokens to build reputation
     */
    function stake(uint256 _amount) external onlyRegistered {
        require(_amount > 0, "Amount must be > 0");

        // Transfer tokens
        require(
            stakeToken.transferFrom(msg.sender, address(this), _amount),
            "Transfer failed"
        );

        // Create stake
        Stake memory newStake = Stake({
            amount: _amount,
            since: block.timestamp,
            unlockTime: block.timestamp + lockPeriod,
            withdrawn: false
        });

        agentStakes[msg.sender].push(newStake);
        agents[msg.sender].totalStaked += _amount;
        totalStaked += _amount;

        // Update reputation
        _updateReputation(msg.sender);

        emit StakeDeposited(msg.sender, _amount, newStake.unlockTime);
    }

    /**
     * @notice Withdraw unlocked stakes
     */
    function withdrawStake(uint256 _stakeIndex) external onlyRegistered {
        require(_stakeIndex < agentStakes[msg.sender].length, "Invalid index");

        Stake storage stakeEntry = agentStakes[msg.sender][_stakeIndex];
        require(!stakeEntry.withdrawn, "Already withdrawn");
        require(block.timestamp >= stakeEntry.unlockTime, "Still locked");

        stakeEntry.withdrawn = true;
        uint256 amount = stakeEntry.amount;

        agents[msg.sender].totalStaked -= amount;
        totalStaked -= amount;

        // Update reputation after unstaking
        _updateReputation(msg.sender);

        require(stakeToken.transfer(msg.sender, amount), "Transfer failed");

        emit StakeWithdrawn(msg.sender, amount);
    }

    /**
     * @notice Record successful covenant completion
     */
    function recordSuccess(address _agent) external onlyAuthorizedSlasher {
        require(agents[_agent].isActive, "Not registered");

        agents[_agent].successfulCovenants++;
        agents[_agent].lastActivity = block.timestamp;

        _updateReputation(_agent);

        // Reward for consistent good behavior
        if (agents[_agent].successfulCovenants % 10 == 0) {
            _distributeReward(_agent);
        }
    }

    /**
     * @notice Record covenant breach and slash
     */
    function recordBreach(
        address _agent, 
        uint256 _slashingMultiplier,
        string calldata _reason
    ) external onlyAuthorizedSlasher {
        require(agents[_agent].isActive, "Not registered");

        agents[_agent].breachedCovenants++;
        agents[_agent].lastActivity = block.timestamp;

        // Calculate slash amount
        uint256 slashAmount = (agents[_agent].totalStaked * 
            slashingPercentage * _slashingMultiplier) / 10000;

        if (slashAmount > 0 && agents[_agent].totalStaked > 0) {
            // Slash from active stakes (oldest first)
            uint256 remainingToSlash = slashAmount;
            Stake[] storage stakes = agentStakes[_agent];

            for (uint256 i = 0; i < stakes.length && remainingToSlash > 0; i++) {
                if (!stakes[i].withdrawn && stakes[i].amount > 0) {
                    uint256 fromThisStake = remainingToSlash > stakes[i].amount 
                        ? stakes[i].amount 
                        : remainingToSlash;

                    stakes[i].amount -= fromThisStake;
                    agents[_agent].totalStaked -= fromThisStake;
                    totalStaked -= fromThisStake;
                    remainingToSlash -= fromThisStake;
                }
            }

            // Transfer slashed amount to fee recipient
            require(
                stakeToken.transfer(feeRecipient, slashAmount - remainingToSlash),
                "Slash transfer failed"
            );
        }

        _updateReputation(_agent);

        emit AgentSlashed(_agent, slashAmount, _reason);
    }

    /**
     * @notice Calculate reputation score
     */
    function calculateReputation(address _agent) public view returns (uint256) {
        AgentProfile storage profile = agents[_agent];

        if (!profile.isActive) return 0;

        // Stake component (0-400 points)
        uint256 stakeScore = profile.totalStaked > 0 
            ? (profile.totalStaked * stakeWeight) / minimumStake 
            : 0;
        if (stakeScore > 400) stakeScore = 400;

        // History component (0-300 points)
        uint256 totalCovenants = profile.successfulCovenants + profile.breachedCovenants;
        uint256 historyScore = 0;
        if (totalCovenants > 0) {
            uint256 successRate = (profile.successfulCovenants * 100) / totalCovenants;
            historyScore = (successRate * historyWeight * 10) / 100; // 0-300
        }

        // Activity component (0-300 points)
        uint256 daysSinceActivity = (block.timestamp - profile.lastActivity) / 1 days;
        uint256 activityScore = daysSinceActivity < 30 
            ? ((30 - daysSinceActivity) * activityWeight * 10) / 30 
            : 0;

        return stakeScore + historyScore + activityScore;
    }

    // ============ Internal Functions ============

    function _updateReputation(address _agent) internal {
        uint256 newScore = calculateReputation(_agent);
        agents[_agent].reputationScore = newScore;
        emit ReputationUpdated(_agent, newScore);
    }

    function _distributeReward(address _agent) internal {
        // Simple reward: 1% of stake back
        uint256 reward = agents[_agent].totalStaked / 100;
        if (reward > 0) {
            require(stakeToken.transfer(_agent, reward), "Reward failed");
            emit RewardDistributed(_agent, reward);
        }
    }

    // ============ Admin Functions ============

    function addSlasher(address _slasher) external {
        require(authorizedSlashers[msg.sender], "Not authorized");
        authorizedSlashers[_slasher] = true;
    }

    function removeSlasher(address _slasher) external {
        require(authorizedSlashers[msg.sender], "Not authorized");
        authorizedSlashers[_slasher] = false;
    }

    function setParameters(
        uint256 _minimumStake,
        uint256 _slashingPercentage,
        uint256 _lockPeriod
    ) external {
        require(authorizedSlashers[msg.sender], "Not authorized");
        minimumStake = _minimumStake;
        slashingPercentage = _slashingPercentage;
        lockPeriod = _lockPeriod;
    }

    // ============ View Functions ============

    function getStakeCount(address _agent) external view returns (uint256) {
        return agentStakes[_agent].length;
    }

    function getStake(address _agent, uint256 _index) 
        external 
        view 
        returns (Stake memory) 
    {
        return agentStakes[_agent][_index];
    }

    function getAgentProfile(address _agent) 
        external 
        view 
        returns (AgentProfile memory) 
    {
        return agents[_agent];
    }

    function isRegistered(address _agent) external view returns (bool) {
        return agents[_agent].isActive;
    }
}

contracts/TaskMarket.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./utils/Pausable.sol";

/**
 * @title TaskMarket
 * @notice Decentralized marketplace for AI agent tasks
 * @dev Agents can post tasks, bid on them, and get paid upon completion
 * Includes ReentrancyGuard and Pausable for security
 */
contract TaskMarket is ReentrancyGuard, Pausable {

    // ============ Enums ============

    enum TaskStatus {
        OPEN,           // Accepting bids
        ASSIGNED,       // Worker selected
        IN_PROGRESS,    // Work started
        COMPLETED,      // Work done, awaiting approval
        DISPUTED,       // Under dispute
        FINISHED,       // Paid and closed
        CANCELLED       // Cancelled by poster
    }

    enum TaskPriority {
        LOW,            // 3 day deadline
        MEDIUM,         // 1 day deadline
        HIGH,           // 4 hour deadline
        URGENT          // 1 hour deadline
    }

    // ============ Structs ============

    struct Task {
        uint256 id;
        address poster;
        string title;
        string description;
        string requirementsIPFS;    // Detailed requirements
        uint256 reward;             // Payment amount
        uint256 collateral;         // Poster collateral
        TaskPriority priority;
        TaskStatus status;
        uint256 createdAt;
        uint256 deadline;
        address assignedTo;
        string resultIPFS;          // Deliverable
        uint256 completedAt;
    }

    struct Bid {
        address bidder;
        uint256 amount;             // Bid amount (can be less than reward)
        uint256 estimatedTime;      // Estimated completion time
        string proposalIPFS;        // Detailed proposal
        uint256 reputation;         // Bidder's reputation score
        uint256 timestamp;
        bool accepted;
    }

    // ============ State Variables ============

    uint256 public nextTaskId = 1;
    mapping(uint256 => Task) public tasks;
    mapping(uint256 => Bid[]) public taskBids;
    mapping(address => uint256[]) public agentTasks;        // Tasks by agent
    mapping(address => uint256) public agentReputation;     // Reputation scores
    mapping(address => uint256) public agentCompletedTasks;
    mapping(address => uint256) public agentTotalEarnings;

    address public feeRecipient;
    uint256 public protocolFeeBps = 250; // 2.5%
    uint256 public minimumReward = 0.001 ether;
    uint256 public cancellationFeeBps = 500; // 5% to cancel

    // Platform stats
    uint256 public totalTasksPosted;
    uint256 public totalTasksCompleted;
    uint256 public totalValueLocked;
    uint256 public totalFeesCollected;

    // ============ Events ============

    event TaskPosted(
        uint256 indexed taskId,
        address indexed poster,
        string title,
        uint256 reward,
        TaskPriority priority,
        uint256 deadline
    );

    event BidSubmitted(
        uint256 indexed taskId,
        address indexed bidder,
        uint256 amount,
        uint256 estimatedTime
    );

    event BidAccepted(
        uint256 indexed taskId,
        address indexed bidder,
        uint256 amount
    );

    event WorkStarted(uint256 indexed taskId, address indexed worker);

    event WorkCompleted(
        uint256 indexed taskId,
        address indexed worker,
        string resultIPFS
    );

    event TaskApproved(
        uint256 indexed taskId,
        address indexed worker,
        uint256 payment
    );

    event TaskDisputed(uint256 indexed taskId, address indexed by, string reason);

    event TaskCancelled(uint256 indexed taskId, uint256 refundAmount);

    event ReputationUpdated(address indexed agent, uint256 newScore);

    // ============ Modifiers ============

    modifier taskExists(uint256 _taskId) {
        require(tasks[_taskId].id != 0, "Task not found");
        _;
    }

    modifier onlyPoster(uint256 _taskId) {
        require(tasks[_taskId].poster == msg.sender, "Not poster");
        _;
    }

    // ============ Constructor ============

    constructor(address _feeRecipient) {
        feeRecipient = _feeRecipient;
    }

    // ============ Core Functions ============

    /**
     * @notice Post a new task
     */
    function postTask(
        string calldata _title,
        string calldata _description,
        string calldata _requirementsIPFS,
        uint256 _reward,
        TaskPriority _priority
    ) external payable whenNotPaused nonReentrant returns (uint256 taskId) {

        require(_reward >= minimumReward, "Reward too low");
        require(msg.value >= _reward, "Insufficient payment");

        // Calculate deadline based on priority
        uint256 duration;
        if (_priority == TaskPriority.LOW) duration = 3 days;
        else if (_priority == TaskPriority.MEDIUM) duration = 1 days;
        else if (_priority == TaskPriority.HIGH) duration = 4 hours;
        else duration = 1 hours;

        taskId = nextTaskId++;

        tasks[taskId] = Task({
            id: taskId,
            poster: msg.sender,
            title: _title,
            description: _description,
            requirementsIPFS: _requirementsIPFS,
            reward: _reward,
            collateral: msg.value,
            priority: _priority,
            status: TaskStatus.OPEN,
            createdAt: block.timestamp,
            deadline: block.timestamp + duration,
            assignedTo: address(0),
            resultIPFS: "",
            completedAt: 0
        });

        agentTasks[msg.sender].push(taskId);
        totalTasksPosted++;
        totalValueLocked += msg.value;

        emit TaskPosted(
            taskId,
            msg.sender,
            _title,
            _reward,
            _priority,
            block.timestamp + duration
        );

        return taskId;
    }

    /**
     * @notice Bid on a task
     */
    function bidOnTask(
        uint256 _taskId,
        uint256 _amount,
        uint256 _estimatedTime,
        string calldata _proposalIPFS
    ) external whenNotPaused nonReentrant taskExists(_taskId) {

        Task storage task = tasks[_taskId];
        require(task.status == TaskStatus.OPEN, "Not open");
        require(block.timestamp < task.deadline, "Deadline passed");
        require(_amount <= task.reward, "Bid exceeds reward");
        require(msg.sender != task.poster, "Cannot bid on own task");

        // Check if already bid
        for (uint256 i = 0; i < taskBids[_taskId].length; i++) {
            require(taskBids[_taskId][i].bidder != msg.sender, "Already bid");
        }

        Bid memory newBid = Bid({
            bidder: msg.sender,
            amount: _amount,
            estimatedTime: _estimatedTime,
            proposalIPFS: _proposalIPFS,
            reputation: agentReputation[msg.sender],
            timestamp: block.timestamp,
            accepted: false
        });

        taskBids[_taskId].push(newBid);

        emit BidSubmitted(_taskId, msg.sender, _amount, _estimatedTime);
    }

    /**
     * @notice Accept a bid and assign task
     */
    function acceptBid(uint256 _taskId, uint256 _bidIndex) 
        external 
        whenNotPaused
        nonReentrant
        taskExists(_taskId) 
        onlyPoster(_taskId) 
    {
        Task storage task = tasks[_taskId];
        require(task.status == TaskStatus.OPEN, "Not open");
        require(_bidIndex < taskBids[_taskId].length, "Invalid bid");

        Bid storage bid = taskBids[_taskId][_bidIndex];
        require(!bid.accepted, "Already accepted");

        bid.accepted = true;
        task.assignedTo = bid.bidder;
        task.status = TaskStatus.ASSIGNED;
        task.reward = bid.amount; // Update to bid amount

        agentTasks[bid.bidder].push(_taskId);

        emit BidAccepted(_taskId, bid.bidder, bid.amount);
    }

    /**
     * @notice Worker starts the task
     */
    function startWork(uint256 _taskId) external taskExists(_taskId) {
        Task storage task = tasks[_taskId];
        require(task.assignedTo == msg.sender, "Not assigned");
        require(task.status == TaskStatus.ASSIGNED, "Not assigned");

        task.status = TaskStatus.IN_PROGRESS;

        emit WorkStarted(_taskId, msg.sender);
    }

    /**
     * @notice Submit completed work
     */
    function submitWork(uint256 _taskId, string calldata _resultIPFS) 
        external 
        taskExists(_taskId) 
    {
        Task storage task = tasks[_taskId];
        require(task.assignedTo == msg.sender, "Not assigned");
        require(task.status == TaskStatus.IN_PROGRESS, "Not in progress");

        task.resultIPFS = _resultIPFS;
        task.completedAt = block.timestamp;
        task.status = TaskStatus.COMPLETED;

        emit WorkCompleted(_taskId, msg.sender, _resultIPFS);
    }

    /**
     * @notice Poster approves work and releases payment
     */
    function approveWork(uint256 _taskId) 
        external 
        whenNotPaused
        nonReentrant
        taskExists(_taskId) 
        onlyPoster(_taskId) 
    {
        Task storage task = tasks[_taskId];
        require(task.status == TaskStatus.COMPLETED, "Not completed");

        task.status = TaskStatus.FINISHED;

        // Calculate payment
        uint256 fee = (task.reward * protocolFeeBps) / 10000;
        uint256 payment = task.reward - fee;

        // Update stats
        totalValueLocked -= task.collateral;
        totalFeesCollected += fee;
        totalTasksCompleted++;

        // Update agent reputation
        agentReputation[task.assignedTo] += 10;
        agentCompletedTasks[task.assignedTo]++;
        agentTotalEarnings[task.assignedTo] += payment;

        // Transfer payment
        (bool success, ) = task.assignedTo.call{value: payment}("");
        require(success, "Payment failed");

        // Transfer fee
        (bool feeSuccess, ) = feeRecipient.call{value: fee}("");
        require(feeSuccess, "Fee transfer failed");

        // Refund excess collateral to poster
        uint256 excess = task.collateral - task.reward;
        if (excess > 0) {
            (bool refundSuccess, ) = task.poster.call{value: excess}("");
            require(refundSuccess, "Refund failed");
        }

        emit TaskApproved(_taskId, task.assignedTo, payment);
        emit ReputationUpdated(task.assignedTo, agentReputation[task.assignedTo]);
    }

    /**
     * @notice Dispute a task
     */
    function disputeTask(uint256 _taskId, string calldata _reason) 
        external 
        taskExists(_taskId) 
    {
        Task storage task = tasks[_taskId];
        require(
            msg.sender == task.poster || msg.sender == task.assignedTo,
            "Not involved"
        );
        require(
            task.status == TaskStatus.IN_PROGRESS || 
            task.status == TaskStatus.COMPLETED,
            "Cannot dispute"
        );

        task.status = TaskStatus.DISPUTED;

        emit TaskDisputed(_taskId, msg.sender, _reason);
    }

    /**
     * @notice Cancel an open task
     */
    function cancelTask(uint256 _taskId) 
        external 
        taskExists(_taskId) 
        onlyPoster(_taskId) 
    {
        Task storage task = tasks[_taskId];
        require(task.status == TaskStatus.OPEN, "Not open");

        task.status = TaskStatus.CANCELLED;

        // Apply cancellation fee
        uint256 fee = (task.collateral * cancellationFeeBps) / 10000;
        uint256 refund = task.collateral - fee;

        totalValueLocked -= task.collateral;
        totalFeesCollected += fee;

        // Transfer fee
        (bool feeSuccess, ) = feeRecipient.call{value: fee}("");
        require(feeSuccess, "Fee transfer failed");

        // Refund poster
        (bool refundSuccess, ) = task.poster.call{value: refund}("");
        require(refundSuccess, "Refund failed");

        emit TaskCancelled(_taskId, refund);
    }

    // ============ View Functions ============

    function getTask(uint256 _taskId) external view returns (Task memory) {
        return tasks[_taskId];
    }

    function getBidCount(uint256 _taskId) external view returns (uint256) {
        return taskBids[_taskId].length;
    }

    function getBids(uint256 _taskId) external view returns (Bid[] memory) {
        return taskBids[_taskId];
    }

    function getAgentTasks(address _agent) external view returns (uint256[] memory) {
        return agentTasks[_agent];
    }

    function getOpenTasks(uint256 _offset, uint256 _limit) 
        external 
        view 
        returns (uint256[] memory) 
    {
        uint256[] memory openTasks = new uint256[](_limit);
        uint256 count = 0;

        for (uint256 i = _offset + 1; i < nextTaskId && count < _limit; i++) {
            if (tasks[i].status == TaskStatus.OPEN) {
                openTasks[count] = i;
                count++;
            }
        }

        // Trim array
        assembly {
            mstore(openTasks, count)
        }

        return openTasks;
    }

    function getAgentStats(address _agent) external view returns (
        uint256 reputation,
        uint256 completed,
        uint256 earnings
    ) {
        return (
            agentReputation[_agent],
            agentCompletedTasks[_agent],
            agentTotalEarnings[_agent]
        );
    }

    // Allow receiving ETH
    receive() external payable {}
}

